PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar, "phone_number" varchar not null, "username" varchar, "email_verified_at" datetime, "password" varchar, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "role" varchar check ("role" in ('superadmin', 'admin', 'user')) not null default 'user', "verification_step" varchar check ("verification_step" in ('unverified', 'step1_complete', 'step2_pending', 'approved')) not null default 'unverified', "profile_picture" varchar);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "user_profile" ("id" integer primary key autoincrement not null, "user_id" integer not null, "full_name" varchar, "navras_naav" varchar, "gender" varchar, "education" varchar, "occupation" varchar, "annual_income" numeric, "date_of_birth" date, "day_and_time_of_birth" varchar, "place_of_birth" varchar, "jaath" varchar, "height_cm__Oonchi" varchar, "skin_complexion__Rang" varchar, "zodiac_sign__Raas" varchar, "naadi" varchar, "gann" varchar, "devak" varchar, "kul_devata" varchar, "fathers_name" varchar, "mothers_name" varchar, "marital_status" varchar, "siblings" varchar, "uncles" varchar, "aunts" varchar, "mumbai_address" text, "village_address" text, "village_farm" varchar, "naathe_relationships" text, "weight_kg" numeric, "created_at" datetime, "updated_at" datetime, "primary_image" integer not null default '1', foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "edit_user_profiles" ("id" integer primary key autoincrement not null, "user_id" integer not null, "full_name" varchar, "navras_naav" varchar, "gender" varchar, "education" varchar, "occupation" varchar, "annual_income" numeric, "date_of_birth" date, "day_and_time_of_birth" varchar, "place_of_birth" varchar, "jaath" varchar, "height_cm__Oonchi" varchar, "skin_complexion__Rang" varchar, "zodiac_sign__Raas" varchar, "naadi" varchar, "gann" varchar, "devak" varchar, "kul_devata" varchar, "fathers_name" varchar, "mothers_name" varchar, "marital_status" varchar, "siblings" varchar, "uncles" varchar, "aunts" varchar, "mumbai_address" text, "village_address" text, "village_farm" varchar, "naathe_relationships" text, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
PRAGMA writable_schema=ON;
CREATE TABLE IF NOT EXISTS sqlite_sequence(name,seq);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE UNIQUE INDEX "users_phone_number_unique" on "users" ("phone_number");
CREATE UNIQUE INDEX "users_username_unique" on "users" ("username");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
PRAGMA writable_schema=OFF;
COMMIT;
